// Выясняем кто что сделал и готовим данные для выполнения действия

// Получаем данные из сообщения (предполагая, что _items определено в вашем окружении)
const message = $input.first().json.callback_query;

// Устройства
const devicesId = {
  "Ванная": "2f9f9cc8-ada2-4bde-bd85-b9885ae28f36",
  "Коридор": "65bcfad0-4759-4cb7-8654-7584b2fc96d0",
  "Кухня": "a56d4cb7-621e-44ba-b825-4e9606a7acb4",
  "Зал": "b0adbe30-5b28-40d1-9bf2-ba15aadd70bb",
  "Спальня": "9af46f0f-c0b5-4604-9240-476eea453f8f",
  "Лента": "",
  "Пылесос": "2d5b0ab8-7880-4d79-a368-6120be845bfc",
  "Шторы": "0197d9e0-ca35-4ea2-a31a-51516c63cdfe",
  "Домофон": "90632374-cc25-4911-81a7-5792fa888a16"
};

// Только верхний свет
const lightUp = [
  "2f9f9cc8-ada2-4bde-bd85-b9885ae28f36",  // Ванная
  "65bcfad0-4759-4cb7-8654-7584b2fc96d0",  // Коридор
  "a56d4cb7-621e-44ba-b825-4e9606a7acb4",  // Кухня
  "b0adbe30-5b28-40d1-9bf2-ba15aadd70bb",  // Зал
  "f6826740-39db-484e-9e3e-2b2a7ed2f5ee"   // Спальня
];

const key = message.data; // Пришло сообщение от кнопки
const deviceAction = key.split("_"); // Устройство и действие

let data = {}; // Ответ (по умолчанию объект)

if (deviceAction.length === 2) {
  let action = null;
  let type = "action";
  let deviceId;
  const [deviceName, actionType] = deviceAction; // Деструктуризация для читаемости

  if (deviceName in devicesId) {
    deviceId = devicesId[deviceName];

    if (actionType === "off") {
      action = false;
    } else if (actionType === "on") {
      action = true;
    } else if (actionType === "scenario") {
      type = "scenario";
      action = "scenario";
    }

  } else {
    // Устройства нет в списке. Возможно это общая команда
    if (deviceName === "Свет") {
      // Общая команда для выключения света
      const responseDataList = [];
      for (const id of lightUp) {
        const cmd = {
          "type": type,
          "action": false,
          "device_id": id,
        };
        responseDataList.push({"json": {"data": cmd}});
      }
      // Внимание: Здесь мы имитируем "return data" из Python, 
      // сразу возвращая массив и завершая выполнение скрипта.
      return responseDataList;
      // data = responseDataList; // Заменяем объект на массив
    }
  }

  // Проверяем и формируем ответ для одиночного действия
  if (action !== null && deviceId) {
    data = {
      "type": type,
      "action": action,
      "device_id": deviceId,
    };
  }
}

return [{"json": {"data": data, "secret": $input.all()[1].json.value}}]; // Итоговый возврат данных, если data не массив

// Кто может управлять
const true_ids = [249503190, 326830581, 203885740];

const query = $input.first().json;

let from_id = 0;
if (query.message) {
  from_id = query.message.from.id;
} else {
  from_id = query.callback_query.from.id;
}

if (true_ids.includes(from_id)) {
  return query;
}

return [{ json: {} }];

